/** Enemy lookup map by id */
export const ENEMY_MAP = new Map<string, Enemy>(ENEMIES.map(e => [e.id, e]));

/** Get all enemies for a zone in order */
export function getEnemiesForZone(zoneId: string): Enemy[] {
    return ENEMIES.filter(e => e.zoneId === zoneId);
}

export default ENEMIES;
